using System.Net;using System.Net.Http.Json;using System.Text.Json;using DBH.UnitTest.Shared;namespace DBH.UnitTest.ApiTests;public class AuditServiceTests_GetAuditLogsByPatient_WithSeedPatient_ShouldReturnResult : ApiTestBase{    protected override IReadOnlyCollection<string> RequiredServices => new[]    {    "AuthService",    "AuditService"    };    [SkippableFact]    public async Task GetAuditLogsByPatient_WithSeedPatient_ShouldReturnResult()    {    await AuthenticateAsAdminAsync(AuditClient);    var response = await GetWithRetryAsync(AuditClient, $"{ApiEndpoints.Audit.ByPatient(TestSeedData.PatientUserId)}?page=1&pageSize=50");        Assert.Equal(HttpStatusCode.OK, response.StatusCode);    var json = await ReadJsonResponseAsync(response);    Assert.True(json.TryGetProperty("data", out _));    }}
